{"file_path":"/home/user/workspace/app/admin/products/page.tsx","content":"import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

/* ── Cached data fetch ──────────────────────────────────────── */
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['admin-products-list'],
  { tags: ['products'] },
);

/* ── Page component ─────────────────────────────────────────── */
export default async function AdminProductsPage() {
  const products = await getCachedProducts();
  const fetchedAt = new Date().toISOString();

  /*
   * Inline Server Action — tagged as "use server" by Next.js.
   * Invalidating the "products" cache tag means every view that
   * tags its fetches with "products" will re-read from the
   * upstream source on the next render, achieving eventual
   * consistency across the admin UI without blocking the current
   * request.
   */
  async function syncCatalog() {
    'use server';
    revalidateTag('products');
  }

  return (
    <div style={styles.page}>
      {/* ── Header + Sync form ─────────────────────── */}
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>Product Catalog</h1>
          <p style={styles.meta}>
            Cached as of{' '}
            <time dateTime={fetchedAt}>
              {new Date(fetchedAt).toLocaleString()}
            </time>
          </p>
        </div>

        <form action={syncCatalog}>
          <button type="submit" style={styles.syncButton}>
            Sync Latest Catalog
          </button>
        </form>
      </div>

      {/* ── Product table ──────────────────────────── */}
      <div style={styles.tableWrapper}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>SKU</th>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Category</th>
              <th style={styles.th}>Price</th>
              <th style={styles.th}>Inventory</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Last Updated</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={styles.tr}>
                <td style={styles.td}>
                  <code style={styles.sku}>{product.sku}</code>
                </td>
                <td style={styles.td}>{product.name}</td>
                <td style={styles.td}>
                  <span style={styles.categoryTag(product.category)}>
                    {product.category}
                  </span>
                </td>
                <td style={styles.td}>
                  ${product.price.toLocaleString()}
                </td>
                <td style={styles.td}>
                  <span style={styles.inventory(product)}>
                    {product.inventory}
                  </span>
                </td>
                <td style={styles.td}>
                  <span style={styles.statusBadge(product.status)}>
                    {product.status.replace('_', ' ')}
                  </span>
                </td>
                <td style={{ ...styles.td, color: '#6b7280' }}>
                  {product.lastUpdated}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
"}

